#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int x, y;
        scanf("%d %d", &x, &y);
        int moves = (x < 0 ? -x : x) + (y < 0 ? -y : y);
        printf("%d\n", moves);
    }
    return 0;
}

