#include <iostream>
using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        int x, y;
        cin >> x >> y;
        int moves = abs(x) + abs(y);
        cout << moves << endl;
    }
    return 0;
}

code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int x = sc.nextInt();
            int y = sc.nextInt();
            int moves = Math.abs(x) + Math.abs(y);
            System.out.println(moves);
        }
    }
}

